import{_ as t,o,c as n,ae as a}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"AMPscript for SFMC Configuration","description":"","frontmatter":{"title":"AMPscript for SFMC Configuration","slug":"ampscript-for-sfmc-configuration"},"headers":[],"relativePath":"developer-hub/ampscript-for-sfmc-configuration.md","filePath":"developer-hub/ampscript-for-sfmc-configuration.md"}'),i={name:"developer-hub/ampscript-for-sfmc-configuration.md"};function l(s,e,r,p,c,d){return o(),n("div",null,[...e[0]||(e[0]=[a(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Salesforce Marketing Cloud allows email marketing teams to create and deploy beautiful templates to send to your customers. Branch integrates with Salesforce Marketing Cloud to enhance the user experience and attribution for your email marketing campaigns. Additionally, you can set up AMPscripts to enhance how you use Branch Links in your email templates in order to drive your users from email links to your app where they are already logged in and reduce the time to conversion.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to use AMPscript for Branch Email, you need to have completed the following:</p><ol><li><a href="./salesforce-marketing-cloud-web-default.html">Salesforce Marketing Cloud Integration.</a></li></ol><h2 id="configure-ampscript" tabindex="-1">Configure AMPscript <a class="header-anchor" href="#configure-ampscript" aria-label="Permalink to &quot;Configure AMPscript&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Domain Usage</p><p>Only use the <code>app.link</code> subdomain assigned to your app as the branch_base_url. Do not use custom subdomains or root domains.</p></div><p>Using Salesforce&#39;s AMPscript, add a new Content Area in Salesforce that converts web links in your email templates into Branch Links.</p><ol><li>Work with your Branch account manager to modify the following Salesforce AMPscript snippet, replaced <code>DOMAIN-HERE</code> with your Branch base domain (i.e. example.app.link)</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%%[ VAR @deeplink, @branch_base_url SET @branch_base_url = &quot;https://DOMAIN-HERE/3p?%243p=e_et&quot; SET @deeplink = CONCAT(@branch_base_url, CONCAT(&quot;&amp;%24original_url=&quot;, URLEncode(@link_to_be_wrapped, 1, 1))) ]%%</span></span></code></pre></div><ol start="2"><li><p>In Salesforce Marketing Cloud, click on <strong>Email Studio</strong> and then <strong>Email</strong></p><p><em>[Image: 1338]</em></p></li><li><p>This will take you to the landing page for the email section. Click on <strong>Content</strong> in the menu bar to navigate to the Content section:</p><p><em>[Image: 1343]</em></p></li><li><p>In the Content section, you will see a list of folders on the left side. Right click on the <strong>My Contents</strong> folder and choose <strong>Create Folder</strong> in the content builder menu:</p><p><em>[Image: 1360]</em></p></li><li><p>Name the folder &quot;Branch&quot;:</p><p><em>[Image: 1830]</em></p></li><li><p>Once the folder is created, in the upper right side, click on <strong>Create</strong> button, then click <strong>Content Blocks</strong> and finally click <strong>Free Form</strong>:</p><p><em>[Image: 2094]</em></p></li><li><p>On the <strong>Free Form</strong> screen, paste in the snippet you previously generated:</p><p><em>[Image: 2094]</em></p></li><li><p>Click <strong>Save</strong>.</p></li><li><p>In the <strong>Create Free Form</strong> window that appears, enter <code>deeplink</code> in the text field named Content Name. Click on Save after you enter the text:</p><p><em>[Image: 2094]</em></p></li><li><p>You will now be back at your list of folders in the Content section with the file <strong>deeplink</strong> listed:<br> You have now successfully created the deep linking AMPscript.</p></li></ol><div class="info custom-block"><p class="custom-block-title">Code Snippet</p><p>The snippet below will follow this format. The code below also has a placeholder for <code>@branch_base_url</code>. Replace it with yours.</p></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%%[ VAR @deeplink, @branch_base_url SET @branch_base_url = &quot;BASE URL FROM BRANCH&quot; SET @deeplink = CONCAT(@branch_base_url, CONCAT(&quot;&amp;%243p=e_et&amp;%24original_url=&quot;, URLEncode(@link_to_be_wrapped, 1, 1))) ]%%</span></span></code></pre></div><h2 id="add-branch-links-with-ampscript" tabindex="-1">Add Branch Links with AMPscript <a class="header-anchor" href="#add-branch-links-with-ampscript" aria-label="Permalink to &quot;Add Branch Links with AMPscript&quot;">​</a></h2><p>Once you have completed configuring your AMPscript, you can now convert individual links in your existing email templates into Branch Links. You will need to do this for all links in your email template that you want to convert to Branch Links.</p><p>For example, if you want to convert the link below into a Branch Link:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;a href=&quot;https://branch.io/product/1234/&quot;&gt; I want it! &lt;/a&gt;</span></span></code></pre></div><p>This is what the link will look like in the email template <strong>after</strong> you add the AMPscript to convert it into a Branch Link:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot; ContentBlockByName(&quot;My Contents\\branch\\deeplink&quot;) ]%%</span></span>
<span class="line"><span>&lt;a href=&quot;%%=RedirectTo(@deeplink)=%%&quot;&gt;Example link&lt;/a&gt;</span></span></code></pre></div><p>The process to convert links into Branch Links using AMPscript is as follows (this flow converts the links in a separate document, and then pastes them back into your final template):</p><ol><li><p>Log in to Salesforce Marketing Cloud</p></li><li><p>Click on <strong>Email Studio</strong> and then a sub-menu will appear. Click on <strong>Email</strong> in the dropdown menu:</p><p><em>[Image: 868]</em></p></li><li><p>This will take you to the landing page for the Email section. Click on Content in the menu bar to navigate to the Content section:</p><p><em>[Image: 1070]</em></p></li><li><p>Navigate to your folder containing your emails and open an existing email. Make sure the email is in HTML layout as shown below:</p><p><em>[Image: 612]</em></p></li><li><p>Choose a link that you want to convert to a Branch deep link. Copy the text right after the <code>href=</code> in your email template, and paste it into a separate document. In the example, it is:</p><p><code>&quot;https://branch.io/product/1234/&quot;</code></p></li><li><p>Add <code>%%[ SET @link_to_be_wrapped =</code> before the link in your separate document. In the example, this is now:</p><p><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot;</code></p></li><li><p>Add <code>ContentBlockByName(&quot;My Contents\\branch\\deeplink&quot;&quot;)]%%</code> after the link:</p><p><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot;ContentBlockByName(&quot;My Contents\\branch\\deeplink&quot;&quot;)]%%</code></p></li><li><p>From the original link in your template, copy the text from and including <code>&lt;a</code> until the <code>href=</code>. Add it to the text after <code>%%</code> in the last step. Please include the <code>&lt;a</code> but not the <code>href=</code>:</p><p><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot; ContentBlockByName(&quot;My Contents\\branch\\deeplink&quot;&quot;) ]%% &lt;a style=&quot;_any css can be added here_&quot;</code></p></li><li><p>Add <code>href=&quot;%%=RedirectTo(@deeplink)=%%&quot;</code> to the end:</p><p><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot; ContentBlockByName(&quot;My Contents\\branch\\deeplink&quot;&quot;) ]%% &lt;a style=&quot;_any css can be added here_&quot; href=&quot;%%=RedirectTo(@deeplink)=%%&quot;</code></p></li><li><p>From the original link in your template, copy the end of the tag, the link text, and the closing tag (<code>&gt;I want it!</code> in the example) and add it to the end:</p><p><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot; ContentBlockByName(&quot;My Contents\\branch\\deeplink&quot;&quot;) ]%% &lt;a style=&quot;_any css can be added here_&quot; href=&quot;%%=RedirectTo(@deeplink)=%%&quot;&gt;I want it!&lt;/a&gt;</code></p></li><li><p>Copy your final result from the separate document back into your email template, replacing everything inside and including the <code>&lt;a&gt;&lt;/a&gt;</code> tags in the template.</p></li><li><p>Repeat this for all your links in your email template that you want to convert to Branch deep links.</p></li></ol><div class="info custom-block"><p class="custom-block-title">Link Conversion Summary</p><p>Wherever you use <code>&lt;a&gt;</code> tags in your email templates, replace those with AMPscript to convert the web URLs into Branch Links. The AMPscript references the <a href="./ampscript-for-salesforce-marketing-cloud.html#add-a-new-content-area-for-easy-deep-linking">Content Area</a> setup earlier.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%%[SET @link_to_be_wrapped = &quot;ADD YOUR LINK HERE&quot; ContentBlockByName(&quot;My Contents\\branch\\deeplink&quot;&quot;)]%%</span></span>
<span class="line"><span>click=&quot;&quot;&gt;</span></span></code></pre></div><p>For example,<br><strong>Before:</strong><br><code>&lt;a href=&quot;https://branch.io/product/1234&quot;&gt;Example link&lt;/a&gt;</code><br><strong>After:</strong><br><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234&quot; ContentBlockByName(&quot;My Contents\\branch\\deeplink&quot;) ]%%</code><br><code>&lt;a href=&quot;%%=RedirectTo(@deeplink)=%%&quot;&gt;Example link&lt;/a&gt;</code></p></div><p>After you convert links into Branch Links in your email templates, you must also add Salesforce&#39;s link attribute <code>mc-deep-link=&quot;true&quot;</code> to your link tags to ensure the app opens in iOS:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;a mc-deep-link=&quot;true&quot; href=&quot;https://my.app.link/3p?$3p=e_et&amp;$original_url=...&quot; &gt; Open App &lt;/a&gt;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Content Area Folder</p><p>Make sure your <code>deeplink</code> Content Area <a href="./ampscript-for-salesforce-marketing-cloud.html#add-a-new-content-area-for-easy-deep-linking">is in the right folder</a>. Either change the folder to &quot;My Contents&quot; or change the path used by &quot;ContentBlockByName&quot; in the Branch script.</p></div>`,25)])])}const m=t(i,[["render",l]]);export{h as __pageData,m as default};
